questions.solutionCode:
function solve(configJson) {
  const config = JSON.parse(configJson);

  // Исправление 1: порядок transforms -- filter должен идти ДО unwrap,
  // иначе unwrap упадет на heartbeat (нет поля after)
  if (config['transforms'] === 'unwrap,filter,mask') {
    config['transforms'] = 'filter,unwrap,mask';
  }

  // Исправление 2: неверный класс Filter.
  // io.debezium.transforms.content.Filter -- не существует,
  // правильный путь: io.debezium.transforms.Filter
  const filterTypeKey = Object.keys(config).find(
    k => k.endsWith('.filter.type')
  );
  if (filterTypeKey && config[filterTypeKey] === 'io.debezium.transforms.content.Filter') {
    config[filterTypeKey] = 'io.debezium.transforms.Filter';
  }

  // Исправление 3: Filter требует language и condition
  const prefix = filterTypeKey ? filterTypeKey.replace('.type', '') : null;
  if (prefix && !config[prefix + '.language']) {
    config[prefix + '.language'] = 'jsr223.groovy';
  }

  return config;
}
